import type { SelectOption } from '@linm-soft/common-components';
import type { LedgerKind } from '../constants/cashVoucherLedgerKind';

const DEFAULT_BY_LEDGER: Record<LedgerKind, Record<string, string>> = {
  Accounting: {
    '1': 'Nhập liệu',
    '3': 'Lập chứng từ',
    '9': 'Hoạch toán sổ cái',
  },
  Warehouse: {
    '1': 'Nhập liệu',
    '3': 'Lập chứng từ',
    '9': 'Ghi sổ',
  },
};

export function formatProcessingLevelLabel(
  code: string | undefined,
  ledgerKind: LedgerKind,
  options: SelectOption[],
): string {
  if (!code) return '—';
  const fromOpts = options.find(o => o.value === code)?.label;
  if (fromOpts) return fromOpts;
  return DEFAULT_BY_LEDGER[ledgerKind][code] ?? `Mức ${code}`;
}
