import { useEffect, useState } from 'react';
import type { LedgerKind } from '../constants/cashVoucherLedgerKind';
import { voucherRegistryService, type VoucherRegistryDto } from '../services/system/voucherRegistryService';

/** Resolve ledgerKind from platform registry API — fallback handled by caller. */
export function useVoucherRegistry(voucherTypeCode: string) {
  const [entry, setEntry] = useState<VoucherRegistryDto | null>(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    let cancelled = false;
    const timer = setTimeout(() => {
      voucherRegistryService
        .getByCode(voucherTypeCode)
        .then(row => {
          if (!cancelled) setEntry(row);
        })
        .catch(() => {
          if (!cancelled) setEntry(null);
        })
        .finally(() => {
          if (!cancelled) setLoading(false);
        });
    }, 0);

    return () => {
      cancelled = true;
      clearTimeout(timer);
    };
  }, [voucherTypeCode]);

  const ledgerKind: LedgerKind | undefined = entry?.ledgerKind;

  return { entry, ledgerKind, loading };
}
